// Package bpf provides Go bindings and event parsing for ebpf-guard's BPF programs.
// Event struct types and parsers live here; BPF object types and loaders are
// generated by bpf2go (see generate.go) and regenerated with `make generate`.

package bpf

import (
	"encoding/binary"
	"fmt"
	"time"

	"github.com/cilium/ebpf"
	"github.com/cilium/ebpf/ringbuf"
	"github.com/zugolO/ebpf-guard/pkg/types"
)

// SyscallEvent matches the C struct event from common.h
// Layout matches packed C struct exactly
type SyscallEvent struct {
	Type      uint32
	Timestamp uint64
	PID       uint32
	TGID      uint32
	UID       uint32
	Comm      [16]byte
	// Union payload - syscall specific
	Nr   int64
	Ret  int64
	Args [6]uint64
}

// NetworkEvent matches the C struct event for network events.
// Wire layout (packed, little-endian):
//
//	[0  ] type         uint32   (4)
//	[4  ] timestamp    uint64   (8)
//	[12 ] pid          uint32   (4)
//	[16 ] tgid         uint32   (4)
//	[20 ] ppid         uint32   (4)
//	[24 ] uid          uint32   (4)
//	[28 ] comm         [16]byte (16)
//	[44 ] parent_comm  [16]byte (16)
//	[60 ] saddr        [16]byte (16)
//	[76 ] daddr        [16]byte (16)
//	[92 ] sport        uint16   (2)
//	[94 ] dport        uint16   (2)
//	[96 ] proto        uint8    (1)
//	[97 ] family       uint8    (1)
type NetworkEvent struct {
	Type       uint32
	Timestamp  uint64
	PID        uint32
	TGID       uint32
	PPID       uint32
	UID        uint32
	Comm       [16]byte
	ParentComm [16]byte
	// Union payload - network specific
	Saddr  [16]byte
	Daddr  [16]byte
	Sport  uint16
	Dport  uint16
	Proto  uint8
	Family uint8 // Address family: 2=AF_INET, 10=AF_INET6
}

// FileaccessEvent matches the C struct event for file events.
// Wire layout (packed, little-endian):
//
//	[0  ] type              uint32  (4)
//	[4  ] timestamp         uint64  (8)
//	[12 ] pid               uint32  (4)
//	[16 ] tgid              uint32  (4)
//	[20 ] ppid              uint32  (4)
//	[24 ] uid               uint32  (4)
//	[28 ] comm              [16]byte (16)
//	[44 ] parent_comm       [16]byte (16)
//	[60 ] filename          [256]byte (256)
//	[316] flags             int32   (4)
//	[320] mode              uint32  (4)
//	[324] op                uint8   (1)
//	[325] fd_path_truncated uint8   (1)   — 1 if filename was truncated at 256 bytes
type FileaccessEvent struct {
	Type        uint32
	Timestamp   uint64
	PID         uint32
	TGID        uint32
	PPID        uint32
	UID         uint32
	Comm        [16]byte
	ParentComm  [16]byte
	Filename    [256]byte
	Flags       int32
	Mode        uint32
	Op          uint8
	FDTruncated uint8
}

// PrivescRawEvent is the wire-format event for EVENT_TYPE_PRIVESC.
// old_caps is in args[0], new_caps in args[1] (reusing the syscall union).
type PrivescRawEvent struct {
	Type       uint32
	Timestamp  uint64
	PID        uint32
	TGID       uint32
	PPID       uint32
	UID        uint32
	Comm       [16]byte
	ParentComm [16]byte
	OldCaps    uint64 // args[0]
	NewCaps    uint64 // args[1]
}

// NetworkCloseRawEvent is the wire-format event for EVENT_TYPE_NET_CLOSE.
// Duration (ns) is encoded in args[0] of the syscall union.
type NetworkCloseRawEvent struct {
	Type       uint32
	Timestamp  uint64
	PID        uint32
	TGID       uint32
	PPID       uint32
	UID        uint32
	Comm       [16]byte
	ParentComm [16]byte
	// Network tuple (from network union)
	Saddr      [16]byte
	Daddr      [16]byte
	Sport      uint16
	Dport      uint16
	Proto      uint8
	Family     uint8
	DurationNs uint64 // encoded in syscall.args[0]
}

// KmodRawEvent is the wire-format event for EVENT_TYPE_KMOD_LOAD.
// Wire layout (packed):
//
//	[0 ] type        uint32 (4)
//	[4 ] timestamp   uint64 (8)
//	[12] pid         uint32 (4)
//	[16] uid         uint32 (4)
//	[20] comm        [16]byte (16)
//	[36] parent_comm [16]byte (16)
//	[52] ppid        uint32  (4)
//	[56] mod_name    [64]byte (64)
//	[120] from_tmpfs uint8 (1)
type KmodRawEvent struct {
	Type       uint32
	Timestamp  uint64
	PID        uint32
	UID        uint32
	Comm       [16]byte
	ParentComm [16]byte
	PPID       uint32
	ModName    [64]byte
	FromTmpfs  uint8
}

