// ParseBpfMonitorEventInto parses a raw ring-buffer sample into an existing
// BpfMonitorRawEvent, avoiding a heap allocation on the hot path.
func ParseBpfMonitorEventInto(raw []byte, out *BpfMonitorRawEvent) error {
	const minSize = 4 + 8 + 4 + 4 + 4 + 4 + 16 + 16 + 4 + 4 + 4 // 72 bytes
	if len(raw) < minSize {
		return fmt.Errorf("bpf_monitor raw sample too small: %d bytes (need %d)", len(raw), minSize)
	}
	off := 0
	out.Type = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.Timestamp = binary.LittleEndian.Uint64(raw[off:])
	off += 8
	out.PID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.TGID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.PPID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.UID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	copy(out.Comm[:], raw[off:off+16])
	off += 16
	copy(out.ParentComm[:], raw[off:off+16])
	off += 16
	out.Cmd = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.ProgType = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.Ret = int32(binary.LittleEndian.Uint32(raw[off:])) /* #nosec G115 */
	return nil
}

// ParseBpfMonitorEvent parses a raw ring-buffer sample for EVENT_TYPE_BPF_PROGRAM.
// For the allocation-free hot path, use ParseBpfMonitorEventInto instead.
func ParseBpfMonitorEvent(raw []byte) (*BpfMonitorRawEvent, error) {
	out := new(BpfMonitorRawEvent)
	return out, ParseBpfMonitorEventInto(raw, out)
}

// ParseTlsClientHelloEventInto parses a raw ring-buffer sample into an existing
// TlsClientHelloRawEvent, avoiding a heap allocation on the hot path.
func ParseTlsClientHelloEventInto(raw []byte, out *TlsClientHelloRawEvent) error {
	const minSize = 4 + 8 + 4 + 4 + 4 + 4 + 16 + 16 + 2 + 2 + 4 + 1 // 69 bytes min
	if len(raw) < minSize {
		return fmt.Errorf("tls_clienthello raw sample too small: %d bytes (need %d)", len(raw), minSize)
	}
	off := 0
	out.Type = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.Timestamp = binary.LittleEndian.Uint64(raw[off:])
	off += 8
	out.PID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.TGID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.PPID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	out.UID = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	copy(out.Comm[:], raw[off:off+16])
	off += 16
	copy(out.ParentComm[:], raw[off:off+16])
	off += 16
	out.Dport = binary.BigEndian.Uint16(raw[off:])
	off += 2 // network byte order
	out.CapturedLen = binary.LittleEndian.Uint16(raw[off:])
	off += 2
	out.OriginalLen = binary.LittleEndian.Uint32(raw[off:])
	off += 4
	if out.CapturedLen > 512 {
		out.CapturedLen = 512
	}
	copy(out.Data[:], raw[off:off+int(out.CapturedLen)])
	return nil
}

// ParseTlsClientHelloEvent parses a raw ring-buffer sample for a ClientHello event.
// For the allocation-free hot path, use ParseTlsClientHelloEventInto instead.
func ParseTlsClientHelloEvent(raw []byte) (*TlsClientHelloRawEvent, error) {
	out := new(TlsClientHelloRawEvent)
	return out, ParseTlsClientHelloEventInto(raw, out)
}

// -----------------------------------------------------------------------
// ToTypesEvent converters
// -----------------------------------------------------------------------

// ToTypesEvent converts a SyscallEvent to types.Event.
func (e *SyscallEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:      types.EventSyscall,
		Timestamp: e.Timestamp,
		PID:       e.PID,
		TGID:      e.TGID,
		UID:       e.UID,
		Comm:      e.Comm,
		Syscall: &types.SyscallEvent{
			Nr:   e.Nr,
			Ret:  e.Ret,
			Args: e.Args,
		},
	}
}

// ToTypesEvent converts a NetworkEvent to types.Event.
func (e *NetworkEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventTCPConnect,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		Network: &types.NetworkEvent{
			Saddr:  e.Saddr,
			Daddr:  e.Daddr,
			Sport:  e.Sport,
			Dport:  e.Dport,
			Proto:  e.Proto,
			Family: types.AddressFamily(e.Family),
		},
	}
}

// ToTypesEvent converts a FileaccessEvent to types.Event.
// FDPath is populated for all ops: for open events it mirrors Filename; for
// read/write events the BPF program resolved it via the fd→path map.
func (e *FileaccessEvent) ToTypesEvent() types.Event {
	fdPath := nullTerminatedString(e.Filename[:])
	return types.Event{
		Type:       types.EventFileAccess,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		File: &types.FileEvent{
			Filename:        e.Filename,
			Flags:           e.Flags,
			Mode:            e.Mode,
			Op:              e.Op,
			FDPath:          fdPath,
			FDPathTruncated: e.FDTruncated != 0,
		},
	}
}

// ToTypesEvent converts a PrivescRawEvent to types.Event.
func (e *PrivescRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventPrivesc,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		Privesc: &types.PrivescEvent{
			OldCaps: e.OldCaps,
			NewCaps: e.NewCaps,
		},
	}
}

// ToTypesEvent converts a NetworkCloseRawEvent to types.Event.
func (e *NetworkCloseRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventNetClose,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		NetClose: &types.NetworkCloseEvent{
			Saddr:    e.Saddr,
			Daddr:    e.Daddr,
			Sport:    e.Sport,
			Dport:    e.Dport,
			Family:   types.AddressFamily(e.Family),
			Duration: time.Duration(e.DurationNs),
		},
	}
}

// ToTypesEvent converts a KmodRawEvent to types.Event.
func (e *KmodRawEvent) ToTypesEvent() types.Event {
	// Trim null bytes from mod name.
	name := e.ModName[:]
	for i, b := range name {
		if b == 0 {
			name = e.ModName[:i]
			break
		}
	}
	return types.Event{
		Type:       types.EventKmodLoad,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		UID:        e.UID,
		PPID:       e.PPID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		Kmod: &types.KmodEvent{
			ModName:   string(name),
			FromTmpfs: e.FromTmpfs != 0,
		},
	}
}

// ToTypesEvent converts a CgroupEscapeRawEvent to types.Event.
func (e *CgroupEscapeRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventCgroupEsc,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		UID:        e.UID,
		PPID:       e.PPID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		CgroupEsc: &types.CgroupEscapeEvent{
			InitCgroupID: e.InitCgroupID,
			NewCgroupID:  e.NewCgroupID,
		},
	}
}

// ToTypesEvent converts an IOUringRawEvent to types.Event.
func (e *IOUringRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventIOUring,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		IOUring: &types.IOUringEvent{
			Op:       e.Op,
			Flags:    e.Flags,
			Fd:       e.Fd,
			ToSubmit: e.ToSubmit,
		},
	}
}

// ToTypesEvent converts a BpfMonitorRawEvent to types.Event.
func (e *BpfMonitorRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventBPFProgram,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		BPFProgram: &types.BPFProgramEvent{
			Cmd:      e.Cmd,
			ProgType: e.ProgType,
			Ret:      e.Ret,
		},
	}
}

// ToTypesEvent converts a TlsClientHelloRawEvent to types.Event.
// The JA3/JA4/JA3S fields are left empty here; they are computed by the
// collector after parsing to avoid circular imports from the ja3 package.
func (e *TlsClientHelloRawEvent) ToTypesEvent() types.Event {
	return types.Event{
		Type:       types.EventTLS,
		Timestamp:  e.Timestamp,
		PID:        e.PID,
		TGID:       e.TGID,
		PPID:       e.PPID,
		UID:        e.UID,
		Comm:       e.Comm,
		ParentComm: e.ParentComm,
		TLS: &types.TLSEvent{
			DataLen: e.OriginalLen,
		},
	}
}

// -----------------------------------------------------------------------
// Helpers
// -----------------------------------------------------------------------

// nullTerminatedString converts a byte slice to a Go string, stopping at the
// first NUL byte. Used to convert fixed-size C string arrays.
func nullTerminatedString(b []byte) string {
	for i, c := range b {
		if c == 0 {
			return string(b[:i])
		}
	}
	return string(b)
}
